/**
 * ViewModeToggle Component - Switch between grouped and flat view
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { LayoutGrid, List } from 'lucide-react';

type ViewMode = 'grouped' | 'flat';

interface ViewModeToggleProps {
  value?: ViewMode;
  onChange?: (mode: ViewMode) => void;
}

export function ViewModeToggle({ value, onChange }: ViewModeToggleProps) {
  const [mode, setMode] = useState<ViewMode>(value || 'grouped');

  useEffect(() => {
    // بارگذاری preference از localStorage
    const saved = localStorage.getItem('pageListViewMode') as ViewMode;
    if (saved && !value) {
      setMode(saved);
      onChange?.(saved);
    }
  }, []);

  const handleChange = (newMode: ViewMode) => {
    setMode(newMode);
    localStorage.setItem('pageListViewMode', newMode);
    onChange?.(newMode);
  };

  return (
    <div className="inline-flex items-center bg-white dark:bg-slate-800 border border-gray-300 dark:border-gray-600 rounded-lg p-1">
      <button
        onClick={() => handleChange('grouped')}
        className={`
          flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded transition-colors
          ${mode === 'grouped'
            ? 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900 dark:text-indigo-200'
            : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
          }
        `}
      >
        <LayoutGrid size={16} />
        Grouped
      </button>
      
      <button
        onClick={() => handleChange('flat')}
        className={`
          flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded transition-colors
          ${mode === 'flat'
            ? 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900 dark:text-indigo-200'
            : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
          }
        `}
      >
        <List size={16} />
        Flat
      </button>
    </div>
  );
}
